full disclosure, I did not extend the current widget, I made a new one.  here is the source:
'''js
var ListBoxView = widgets.DOMWidgetView.extend({
    initialize: function (options) {
        //console.log('hello from src init!');
        ListBoxView.__super__.initialize.apply(this, arguments);
        this.listenTo(this.model, 'change:options', this.loadOptions, this);
        this.listenTo(this.model, 'change:tooltips', this.loadOptions, this);
        this.listenTo(this.model, 'change:selected', this.selectedChanged, this);
    },
    render: function() {            
            //console.log("hello from render!");
            var allowMultiple = new Boolean(this.model.get('allowMultiple'));            
        
            if (allowMultiple == true)
            {    
                this.lb_select = $('<select multiple class="listboxselect" style="width:' + this.model.get('width') + ';z-index:1;" size="' + this.model.get('size') + '"/>');
            }
            else 
            {
                this.lb_select = $('<select class="listboxselect" style="width:' + this.model.get('width') + ';z-index:1;" size="' + this.model.get('size') + '"/>');
            }
            this.loadOptions();
            this.setElement( $(this.lb_select) );
    },
    loadOptions: function() {
            //console.log("hello from loadOptions!");
            //var start = new Date().getTime();
            var opts=this.model.get('options');
            var tips=this.model.get('tooltips');
            //console.log('Load time 0: ' + (new Date().getTime() - start));
            var index;
            var strHTML = "";
        
            $(this.lb_select).empty();
            var optsHTML = [];
            for (index = 0; index < opts.length; ++index) {        
                var sopt = ""
                if (tips == null || tips.length == 0)
                {
                    strHTML += sopt.concat('<option value="', opts[index], '" >', opts[index], '</option>');
                    //optsHTML.push('<option value="' + opts[index] + '" >' + opts[index] + '</option>');
                }
                else
                {
                    strHTML += sopt.concat('<option value="', opts[index], '" title="', tips[index], '" >', opts[index], '</option>');
                    //optsHTML.push('<option value="' + opts[index] + '" title="' + tips[index] + '" >' + opts[index] + '</option>');
                }
            } 
            //$(this.lb_select).append(optsHTML.join('\n'));
            //$(this.lb_select).html(optsHTML.join(''));
            $(this.lb_select).html(strHTML);
            this.model.set('selected', null );
            this.touch();
            //console.log('Load time 2: ' + (new Date().getTime() - start));
            return ListBoxView.__super__.update.apply(this);
    },
    selectedChanged: function() {            
            var allowMultiple = new Boolean(this.model.get('allowMultiple'));
            var selected = this.model.get('selected');
            if (selected == null){
                $(this.lb_select).get(0).selectedIndex = -1;
            }
            else 
            {
                //reconcile desired selection against available options
                //update model selected property accordingly
                var opts = this.model.get('options').map(String);
                var selectedActual = [];
                if (Array.isArray(selected)) {
                    for (var j = 0; j < selected.length; ++j) {                  
                        if(jQuery.inArray(String(selected[j]), opts) !== -1)
                            selectedActual.push(String(selected[j]));
                        else
                            console.log("item not found in available options:" + String(selected[j]));
                    }
                }
                else {
                    //selected is not an array    
                    if(jQuery.inArray(String(selected), opts) !== -1)
                        selectedActual.push(String(selected));
                    else
                        console.log("item not found in available options:" + String(selected));
                }
                
                if (allowMultiple == true) {
                    this.model.set('selected', selectedActual );
                    $(this.lb_select).val(selectedActual);
                }
                else {
                    this.model.set('selected', selectedActual[0] );
                    $(this.lb_select).val(selectedActual[0]);
                }
            }
            this.touch();
        
            return ListBoxView.__super__.update.apply(this);
    },
    events: {
            // List of events and their handlers.
            'change': 'handle_change', 'dblclick':'handle_dblclick', 'keypress':'handle_dblclick', 'scroll':'handle_scroll'
    },
    handle_change: function(event, ui) {
        var allowMultiple = new Boolean(this.model.get('allowMultiple'));
        values = $(this.lb_select).val();
        
        if (allowMultiple == true) {
            this.model.set('selected', values);
        }
        else {
            if (Array.isArray(values))
                this.model.set('selected', String(values[0]));
            else
                this.model.set('selected', String(values));
        }
        
        //update model
        this.touch();
        
        //update UI
        //return ListBoxView.__super__.update.apply(this);
    },
    handle_keypress: function(event) {
        if(event.key == 13){
            var opts=this.model.get('options');
            var val=opts[$(this.lb_select).get(0).selectedIndex];
            this.model.set('value', val);
            this.model.set('dblclickevent', {'value':event.target.value, 'type': event.type , 'name':event.originalEvent , 'timeStamp':event['timeStamp']});            
            this.touch();            
        }
    },
    handle_dblclick: function(event) {                   
        var opts=this.model.get('options');
        var val = null;
        var sel_idx = $(this.lb_select).get(0).selectedIndex;
        if (sel_idx > -1)
        {
            val = opts[sel_idx];
        }
        this.model.set('value', val);
        this.model.set('dblclickevent', {'value':event.target.value, 'type': event.type , 'name':event.originalEvent , 'timeStamp':event['timeStamp']});            
        this.touch();            
    },
    handle_scroll: function(event, ui) {
        
        if(event.target.offsetHeight + event.target.scrollTop >= event.target.scrollHeight)
        {
            console.log("End");
        }
    }
    
});
'''
